import fs from 'fs';
import path from 'path';
import { LlamaCloud } from '@llamaindex/llama-cloud';

async function main() {
    const trialId = fs.readFileSync('/logs/artifacts/trial_id', 'utf-8').trim();
    const logFile = '/home/user/composite_retriever/output.log';
    const client = new LlamaCloud({
        token: process.env.LLAMA_CLOUD_API_KEY
    });

    const logStream = fs.createWriteStream(logFile);
    const log = (msg: string) => {
        console.log(msg);
        logStream.write(msg + '\n');
    };

    log(`Trial ID: ${trialId}`);

    const createPipeline = async (name: string, description: string, dataDir: string) => {
        const pipeline = await client.pipelines.upsert({
            name,
            embeddingConfig: {
                type: 'OPENAI_EMBEDDING',
                component: {
                    modelName: 'text-embedding-3-small',
                    apiKey: process.env.OPENAI_API_KEY
                }
            },
            dataSinkId: null
        });

        const files = fs.readdirSync(dataDir);
        const fileIds: string[] = [];
        for (const fileName of files) {
            const filePath = path.join(dataDir, fileName);
            const fileResponse = await client.files.create({
                file: fs.createReadStream(filePath),
                purpose: 'user_data'
            });
            fileIds.push(fileResponse.id);
        }

        await client.pipelines.files.create(pipeline.id, {
            body: fileIds.map(id => ({ fileId: id }))
        });

        return { id: pipeline.id, name, description };
    };

    const policiesPipeline = await createPipeline(`policies-${trialId}`, "Contains company policy documents including vacation and remote work info", '/home/user/composite_retriever/data/policies');
    log(`Policies Pipeline ID: ${policiesPipeline.id}`);

    const faqPipeline = await createPipeline(`faq-${trialId}`, "Contains frequently asked questions about office location and password resets", '/home/user/composite_retriever/data/faq');
    log(`FAQ Pipeline ID: ${faqPipeline.id}`);

    const waitForPipeline = async (pipelineId: string) => {
        while (true) {
            const status = await client.pipelines.getStatus(pipelineId);
            if (status.status !== 'NOT_STARTED' && status.status !== 'IN_PROGRESS') {
                break;
            }
            await new Promise(resolve => setTimeout(resolve, 5000));
        }
    };

    await Promise.all([waitForPipeline(policiesPipeline.id), waitForPipeline(faqPipeline.id)]);

    const retriever = await client.retrievers.create({
        name: `composite-retriever-${trialId}`,
        pipelines: [
            { pipelineId: policiesPipeline.id, description: policiesPipeline.description },
            { pipelineId: faqPipeline.id, description: faqPipeline.description }
        ]
    });
    log(`Composite Retriever ID: ${retriever.id}`);

    const query = "What is the vacation policy and where is the office located?";
    log(`Query: ${query}`);

    const results = await client.retrievers.retriever.search(retriever.id, {
        query,
        mode: 'full',
        rerankTopN: 5
    });

    log(`Result Count: ${results.nodes.length}`);
    for (const node of results.nodes) {
        log(`Node Score: ${node.score} | Text: ${node.text.substring(0, 80).replace(/\n/g, ' ')}`);
    }

    logStream.end();
}

main().catch(err => {
    console.error(err);
    process.exit(1);
});

